sect2.programlisting:
SELECT pcid(PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0]));
-- 1
SELECT getX(PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0])),
       getY(PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0])),
       getZ(PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0]));
-- 10 | 20 | 30

sect1.programlisting:
SELECT numValues(set(ARRAY[
  PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0]),
  PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0]),  -- duplicate, deduped
  PC_MakePoint(1, ARRAY[11.0, 21.0, 31.0])
]));
-- 2

sect2.programlisting:
-- An instant
SELECT tpcpoint(PC_MakePoint(1, ARRAY[10.0, 20.0, 30.0]),
                '2024-01-01 12:00:00+00');
-- A discrete sequence of three instants
SELECT tpcpointSeq(ARRAY[
  tpcpoint(PC_MakePoint(1, ARRAY[1.0, 2.0, 3.0]), '2024-01-01'::timestamptz),
  tpcpoint(PC_MakePoint(1, ARRAY[4.0, 5.0, 6.0]), '2024-01-02'::timestamptz),
  tpcpoint(PC_MakePoint(1, ARRAY[7.0, 8.0, 9.0]), '2024-01-03'::timestamptz)
], 'step');
